package com.interview.lld.moviebooking.model;

// ── WHY THIS ENUM ────────────────────────────────────────────────────────────
// Every seat for a given showtime is in exactly one of these three states.
// Keeping the vocabulary in one place means the state machine in ShowSeat is the
// ONLY thing that decides which transitions are legal.
// 🎙️ "A seat is either free to grab, held by someone who is paying, or booked.
//      Those are the only three states — everything else is illegal."
public enum SeatStatus {
    AVAILABLE,  // nobody holds it — free to grab
    HELD,       // someone reserved it and has 10 minutes to pay
    BOOKED      // paid for — final, never changes again
}

package com.interview.lld.moviebooking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// One base exception for the whole booking domain. Every specific failure
// (seat taken, unknown showtime, hold expired) extends this, so a caller can
// catch the whole family with one catch block, or each kind individually.
// 🎙️ "I give the domain one base exception. Every booking failure is a subclass,
//      so callers never have to catch a bare RuntimeException from my code."
public class BookingException extends RuntimeException {
    public BookingException(String message) {
        super(message);
    }
}

package com.interview.lld.moviebooking.model;

import java.util.List;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown when a multi-seat hold cannot be fully satisfied — at least one of the
// requested seats is already HELD or BOOKED. It carries WHICH seats blocked the
// request so the caller can tell the user "A3 and A4 are taken" instead of a
// vague failure.
// 🎙️ "When even one requested seat is taken I reject the whole request and tell
//      the user exactly which seats blocked it — all-or-nothing, with a reason."
public class SeatsUnavailableException extends BookingException {
    private final List<String> conflictingSeats;

    public SeatsUnavailableException(List<String> conflictingSeats) {
        super("Seats unavailable: " + conflictingSeats);
        this.conflictingSeats = List.copyOf(conflictingSeats);
    }

    public List<String> getConflictingSeats() {
        return conflictingSeats;
    }
}

package com.interview.lld.moviebooking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown when a caller passes a showtime id the system has never heard of.
// We reject at the boundary BEFORE touching any state.
// 🎙️ "Unknown showtime id is rejected up front — I never let a bad id reach the
//      booking logic."
public class UnknownShowtimeException extends BookingException {
    public UnknownShowtimeException(String showtimeId) {
        super("Unknown showtime: " + showtimeId);
    }
}

package com.interview.lld.moviebooking.model;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Thrown for bad inputs that are not about seat availability: empty seat list,
// unknown seat label, unknown hold id, or trying to confirm a hold that already
// expired. Validation failures that are the CALLER's fault, not a race.
// 🎙️ "This is for caller mistakes — empty request, a seat label that does not
//      exist on this screen, or confirming a hold that already timed out."
public class InvalidBookingException extends BookingException {
    public InvalidBookingException(String message) {
        super(message);
    }
}

package com.interview.lld.moviebooking.model;

import java.time.Instant;

import javax.annotation.Nullable;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// One seat, for ONE showtime. This is the heart of the system: it is the ONLY
// class allowed to change a seat's status. The booking service never writes
// `seat.status = BOOKED` directly — it calls hold(), confirm(), release(). That
// way illegal jumps (AVAILABLE straight to BOOKED, or BOOKED back to AVAILABLE)
// are impossible by construction.
// 🎙️ "ShowSeat is a tiny state machine. The service asks it to hold, confirm or
//      release — it never pokes the status field directly. So an illegal jump
//      like 'available straight to booked' simply cannot happen."
public class ShowSeat {

    private final String seatLabel;        // e.g. "A1" — stable id within a showtime
    private SeatStatus status;
    @Nullable private String heldBy;       // hold id that owns this seat while HELD
    @Nullable private Instant heldUntil;   // when this hold expires (10 min after hold)

    public ShowSeat(String seatLabel) {
        this.seatLabel = seatLabel;
        this.status = SeatStatus.AVAILABLE;
    }

    public String getSeatLabel() {
        return seatLabel;
    }

    public SeatStatus getStatus() {
        return status;
    }

    @Nullable
    public String getHeldBy() {
        return heldBy;
    }

    @Nullable
    public Instant getHeldUntil() {
        return heldUntil;
    }

    // WHY: a seat can be grabbed only if it is AVAILABLE. A seat that is HELD or
    //      BOOKED is not free. This single check is what the two-phase commit
    //      relies on — the service checks isAvailable() on ALL seats first.
    public boolean isAvailable() {
        return status == SeatStatus.AVAILABLE;
    }

    // WHY: move AVAILABLE -> HELD and stamp who holds it and until when.
    //      We assert the precondition so a caller that skipped the availability
    //      check cannot silently corrupt the state machine.
    public void hold(String holdId, Instant until) {
        if (status != SeatStatus.AVAILABLE) {
            throw new InvalidBookingException(
                "Cannot hold seat " + seatLabel + " in status " + status);
        }
        this.status = SeatStatus.HELD;
        this.heldBy = holdId;
        this.heldUntil = until;
    }

    // WHY: move HELD -> BOOKED, but ONLY for the hold that actually owns the seat.
    //      If a different hold id tries to confirm, we reject — you cannot pay for
    //      a seat someone else is holding.
    // ⚠️ FOLLOW-UP: "What if the hold already expired when they pay?"
    //    → "The service checks expiry before calling confirm. If the sweeper
    //       already released it, the seat is AVAILABLE and this throws."
    public void confirm(String holdId) {
        if (status != SeatStatus.HELD || !holdId.equals(heldBy)) {
            throw new InvalidBookingException(
                "Cannot confirm seat " + seatLabel + " for hold " + holdId);
        }
        this.status = SeatStatus.BOOKED;
        this.heldBy = null;
        this.heldUntil = null;
    }

    // WHY: send the seat back to AVAILABLE. This is "safe to call twice — second
    //      call does nothing" on purpose: the 10-minute sweeper and an explicit
    //      cancel can race, both deciding the hold is dead. Whichever runs first
    //      frees the seat; the second sees it is already AVAILABLE and returns.
    //      A BOOKED seat is final and is never released.
    // ⚠️ FOLLOW-UP: "What if release races with confirm?"
    //    → "Both run under the per-showtime lock, so they are ordered. If confirm
    //       wins, the seat is BOOKED and release leaves it alone."
    public void release() {
        if (status == SeatStatus.HELD) {
            this.status = SeatStatus.AVAILABLE;
            this.heldBy = null;
            this.heldUntil = null;
        }
    }
}

package com.interview.lld.moviebooking.model;

import java.util.Collection;
import java.util.LinkedHashMap;
import java.util.Map;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// A single screening: one movie, on one screen, at one time. It owns the grid of
// ShowSeat objects for that screening. The booking service holds and books seats
// THROUGH this object — a Showtime is the natural unit of contention, because two
// people fighting over a seat are always fighting over a seat in the SAME showtime.
// That is exactly why the lock in §9 is per-showtime.
// 🎙️ "A showtime is one screening and it owns its own seats. Two users can only
//      collide if they want a seat in the same showtime — so the showtime is the
//      thing I lock."
public class Showtime {

    private final String showtimeId;
    private final String movieTitle;       // descriptive only — kept for the ticket
    private final Map<String, ShowSeat> seats;  // seat label -> ShowSeat

    public Showtime(String showtimeId, String movieTitle, Collection<String> seatLabels) {
        this.showtimeId = showtimeId;
        this.movieTitle = movieTitle;
        // WHY: LinkedHashMap keeps seat order stable (A1, A2, A3...) so demos and
        //      tests read predictably. A plain HashMap would scramble the order.
        this.seats = new LinkedHashMap<>();
        for (String label : seatLabels) {
            this.seats.put(label, new ShowSeat(label));
        }
    }

    public String getShowtimeId() {
        return showtimeId;
    }

    public String getMovieTitle() {
        return movieTitle;
    }

    // WHY: look up one seat by label. Returns null for an unknown label; the
    //      service turns that into a typed InvalidBookingException so callers
    //      never see a raw null.
    public ShowSeat getSeat(String label) {
        return seats.get(label);
    }

    public Collection<ShowSeat> allSeats() {
        return seats.values();
    }
}

package com.interview.lld.moviebooking.model;

import java.time.Instant;
import java.util.List;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// A temporary claim on a set of seats. When a user picks seats, they get a
// SeatHold back: a hold id, the seats it covers, and an expiry timestamp 10 min
// out. They confirm with this hold id to pay. The sweeper uses expiresAt to find
// dead holds. It is a value object — once created it never changes; we replace
// it, never mutate it.
// 🎙️ "A hold is a temporary claim. It carries the seats, who owns it, and when it
//      dies. It is immutable — the seats' status lives on the seats, not here."
public record SeatHold(
        String holdId,
        String showtimeId,
        List<String> seatLabels,
        Instant expiresAt) {

    // WHY: defensive copy so a caller cannot mutate the seat list after the hold
    //      is issued. A hold is a promise — it must not change under us.
    public SeatHold {
        seatLabels = List.copyOf(seatLabels);
    }

    // WHY: time is passed IN, never read from the wall clock here. The sweeper and
    //      confirm() both ask "is this hold expired as of `now`?" using the SAME
    //      injected clock, so tests can fast-forward without sleeping.
    public boolean isExpired(Instant now) {
        return !now.isBefore(expiresAt);   // now >= expiresAt
    }
}

package com.interview.lld.moviebooking.model;

import java.time.Instant;
import java.util.List;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The proof of a completed booking. Issued only after payment succeeds and every
// seat flips to BOOKED. It is a frozen record — once a ticket exists, nothing can
// change it. That mirrors real life: a confirmed ticket is final.
// 🎙️ "A ticket is the receipt for a confirmed booking. It is a record — immutable
//      — because a booked ticket should never change after it is issued."
public record Ticket(
        String ticketId,
        String showtimeId,
        String movieTitle,
        List<String> seatLabels,
        Instant bookedAt) {

    public Ticket {
        seatLabels = List.copyOf(seatLabels);
    }
}

package com.interview.lld.moviebooking.gateway;

import java.time.Instant;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// Time is a dependency, not a global. The service asks the Clock "what time is
// it now?" instead of calling Instant.now() directly. In production we inject a
// real clock; in tests we inject a fake clock we can jump forward 10 minutes with
// no actual waiting. This is what makes hold-expiry testable in milliseconds.
// 🎙️ "I pass the clock in as a tiny interface. Tests use a fake clock and move it
//      forward 10 minutes instantly — I never sleep in a test."
public interface Clock {
    Instant now();

    // A real wall-clock for production / the Main demo.
    static Clock system() {
        return Instant::now;
    }
}

package com.interview.lld.moviebooking.gateway;

import java.time.Duration;
import java.time.Instant;
import java.util.concurrent.atomic.AtomicReference;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// A fake clock for tests and the Main demo. It starts at a fixed instant and can
// be advanced by any duration. That lets us prove "a hold expires after 10
// minutes" by jumping forward 11 minutes instantly — no Thread.sleep, no flaky
// timing. It is thread-safe (AtomicReference) so the concurrency test can share it.
// 🎙️ "This is the fake clock. advance(11 minutes) lets me test expiry without
//      ever waiting — the whole suite runs in milliseconds."
public final class MutableClock implements Clock {

    private final AtomicReference<Instant> current;

    public MutableClock(Instant start) {
        this.current = new AtomicReference<>(start);
    }

    @Override
    public Instant now() {
        return current.get();
    }

    // WHY: move the clock forward. Tests call this to make a hold expire on demand.
    public void advance(Duration delta) {
        current.updateAndGet(t -> t.plus(delta));
    }
}

package com.interview.lld.moviebooking.service;

import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicInteger;

import com.interview.lld.moviebooking.gateway.Clock;
import com.interview.lld.moviebooking.model.InvalidBookingException;
import com.interview.lld.moviebooking.model.SeatHold;
import com.interview.lld.moviebooking.model.SeatStatus;
import com.interview.lld.moviebooking.model.SeatsUnavailableException;
import com.interview.lld.moviebooking.model.ShowSeat;
import com.interview.lld.moviebooking.model.Showtime;
import com.interview.lld.moviebooking.model.Ticket;
import com.interview.lld.moviebooking.model.UnknownShowtimeException;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The brain. It coordinates every operation: hold seats, confirm payment, cancel,
// and sweep expired holds. It owns the registry of showtimes and the registry of
// live holds. It does NOT change seat status itself — it asks each ShowSeat to
// hold/confirm/release, so the state-machine rules live in one place.
//
// This is the CLEAN, single-threaded core. There are ZERO locks in this file.
// The thread-safe version (§9, ThreadSafeBookingService) is a subclass that
// overrides ONE pair of hook methods. That keeps the OO design the star here.
//
// 🎙️ "BookingService is the orchestrator. It holds the showtimes and the live
//      holds, and it drives the seat state machine. There is no lock code in this
//      file at all — the thread-safe version is a subclass that overrides two
//      tiny hooks."
public class BookingService {

    // 10-minute hold window. A held seat the user does not pay for is released
    // after this. Configurable per-instance so tests can shrink it if needed.
    public static final Duration HOLD_DURATION = Duration.ofMinutes(10);

    private final Clock clock;
    private final Duration holdDuration;

    // showtime id -> Showtime. Showtimes are registered once at setup.
    private final Map<String, Showtime> showtimes = new ConcurrentHashMap<>();

    // hold id -> SeatHold. The orchestrator owns the truth about every live hold,
    // so the sweeper can enumerate them and confirm() can look one up in O(1).
    private final Map<String, SeatHold> holds = new ConcurrentHashMap<>();

    // WHY: counter-based ids (hold-1, tkt-2) make test assertions readable. In
    //      production I would switch to UUIDs. AtomicInteger so id minting is safe
    //      even before any lock is held.
    private final AtomicInteger holdCounter = new AtomicInteger(0);
    private final AtomicInteger ticketCounter = new AtomicInteger(0);

    public BookingService(Clock clock) {
        this(clock, HOLD_DURATION);
    }

    public BookingService(Clock clock, Duration holdDuration) {
        this.clock = clock;
        this.holdDuration = holdDuration;
    }

    // WHY: register a screening up front. Setup-time, not part of the booking
    //      hot path, so no lock needed.
    public void addShowtime(Showtime showtime) {
        showtimes.put(showtime.getShowtimeId(), showtime);
    }

    // ── Public op 1: holdSeats ───────────────────────────────────────────────
    // WHY: this is the two-phase commit. Phase 1: CHECK every requested seat is
    //      AVAILABLE. Phase 2: only if ALL pass, HOLD every seat. If even one is
    //      taken, we touch nothing and throw with the conflicting labels. That is
    //      the all-or-nothing rule the problem cares about.
    public SeatHold holdSeats(String showtimeId, List<String> seatLabels) {
        Showtime showtime = requireShowtime(showtimeId);
        validateSeatRequest(showtime, seatLabels);

        // gateLock() does NOTHING in this clean class. The thread-safe subclass
        // overrides it to take the per-showtime lock around the whole check+hold.
        gateLock(showtimeId);
        try {
            List<ShowSeat> targets = resolveSeats(showtime, seatLabels);

            // PHASE 1 — CHECK all. Collect every seat that is not free.
            List<String> conflicts = new ArrayList<>();
            for (ShowSeat seat : targets) {

                if (!seat.isAvailable()) {
                    conflicts.add(seat.getSeatLabel());
                }
            }
            if (!conflicts.isEmpty()) {
                // WHY: back out without holding anything. No seat was touched, so
                //      there is nothing to roll back — that is the whole point of
                //      checking all BEFORE holding any.
                throw new SeatsUnavailableException(conflicts);
            }

            // PHASE 2 — HOLD all. Every seat passed, so this cannot fail midway.
            String holdId = "hold-" + holdCounter.incrementAndGet();
            Instant expiresAt = clock.now().plus(holdDuration);
            for (ShowSeat seat : targets) {
                seat.hold(holdId, expiresAt);
            }
            SeatHold hold = new SeatHold(holdId, showtimeId, seatLabels, expiresAt);
            holds.put(holdId, hold);
            return hold;
        } finally {
            gateUnlock(showtimeId);
        }
    }

    // ── Public op 2: confirmBooking ──────────────────────────────────────────
    // WHY: turn a live hold into a paid ticket. Guard the expiry FIRST so a hold
    //      that timed out (or was swept) can never be confirmed. Then flip every
    //      held seat to BOOKED and issue the immutable ticket.
    public Ticket confirmBooking(String holdId) {
        Showtime showtime;
        SeatHold hold;

        gateLockForHold(holdId);
        try {
            hold = holds.get(holdId);
            if (hold == null) {
                throw new InvalidBookingException("Unknown or already-used hold: " + holdId);
            }
            // WHY: if the hold already expired, release its seats now and reject.
            //      No window where a stale hold still books a seat.
            if (hold.isExpired(clock.now())) {
                releaseHold(hold);
                holds.remove(holdId);
                throw new InvalidBookingException("Hold expired: " + holdId);
            }
            showtime = showtimes.get(hold.showtimeId());
            for (String label : hold.seatLabels()) {
                showtime.getSeat(label).confirm(holdId);
            }
            holds.remove(holdId);
        } finally {
            gateUnlockForHold(holdId);
        }

        String ticketId = "tkt-" + ticketCounter.incrementAndGet();
        return new Ticket(ticketId, hold.showtimeId(), showtime.getMovieTitle(),
                hold.seatLabels(), clock.now());
    }

    // ── Public op 3: cancelHold ──────────────────────────────────────────────
    // WHY: a user backed out before paying. Release the seats and drop the hold.
    //      Safe to call on an unknown/already-gone hold — it just does nothing.
    public void cancelHold(String holdId) {
        gateLockForHold(holdId);
        try {
            SeatHold hold = holds.remove(holdId);
            if (hold != null) {
                releaseHold(hold);
            }
        } finally {
            gateUnlockForHold(holdId);
        }
    }

    // ── Public op 4: sweepExpiredHolds ───────────────────────────────────────
    // WHY: the background cleanup. A timer thread calls this every minute. It
    //      finds holds older than 10 minutes and releases their seats so the
    //      seats go back on sale. Idempotent — each pass is independent, and
    //      releasing an already-freed seat is a no-op.
    // 🎙️ "This runs in the background. It scans live holds, and any that passed
    //      their 10-minute mark get released. Running it twice does no harm."
    public int sweepExpiredHolds() {
        Instant now = clock.now();
        int released = 0;
        // Snapshot the ids so we are not iterating the map while removing from it.
        List<String> holdIds = new ArrayList<>(holds.keySet());
        for (String holdId : holdIds) {

            gateLockForHold(holdId);
            try {
                SeatHold hold = holds.get(holdId);
                if (hold != null && hold.isExpired(now)) {
                    releaseHold(hold);
                    holds.remove(holdId);
                    released++;
                }
            } finally {
                gateUnlockForHold(holdId);
            }
        }
        return released;
    }

    // ── Read helper used by demos / tests ────────────────────────────────────
    public long countByStatus(String showtimeId, SeatStatus status) {
        Showtime showtime = requireShowtime(showtimeId);
        return showtime.allSeats().stream().filter(s -> s.getStatus() == status).count();
    }

    public int liveHoldCount() {
        return holds.size();
    }

    // ── Private helpers ──────────────────────────────────────────────────────

    private Showtime requireShowtime(String showtimeId) {
        Showtime showtime = showtimes.get(showtimeId);
        if (showtime == null) {
            throw new UnknownShowtimeException(showtimeId);
        }
        return showtime;
    }

    // WHY: validate the request shape BEFORE mutating anything — empty list and
    //      unknown seat labels are caller mistakes, rejected with a clear error.
    private void validateSeatRequest(Showtime showtime, List<String> seatLabels) {
        if (seatLabels == null || seatLabels.isEmpty()) {
            throw new InvalidBookingException("Must request at least one seat");
        }
        for (String label : seatLabels) {
            if (showtime.getSeat(label) == null) {
                throw new InvalidBookingException(
                    "Unknown seat " + label + " for showtime " + showtime.getShowtimeId());
            }
        }
    }

    private List<ShowSeat> resolveSeats(Showtime showtime, List<String> seatLabels) {
        List<ShowSeat> seats = new ArrayList<>(seatLabels.size());
        for (String label : seatLabels) {
            seats.add(showtime.getSeat(label));
        }
        return seats;
    }

    // WHY: release every seat a hold covers. Used by cancel, the expiry guard in
    //      confirm, and the sweeper — one place, so the rule is canonical.
    private void releaseHold(SeatHold hold) {
        Showtime showtime = showtimes.get(hold.showtimeId());
        if (showtime == null) {
            return;
        }
        for (String label : hold.seatLabels()) {
            ShowSeat seat = showtime.getSeat(label);
            if (seat != null) {
                seat.release();
            }
        }
    }

    // ── Template-method hooks (no-ops here; overridden in §9) ─────────────────
    // WHY: these four methods do NOTHING in this clean class. The thread-safe
    //      subclass overrides them to take/release a per-showtime lock. This file
    //      has zero lock imports — the concurrency story is entirely in the
    //      subclass, so the diff between "clean" and "thread-safe" is tiny.
    // 🎙️ "These hooks are empty here. The thread-safe subclass replaces them with
    //      a real per-showtime lock. My core has no lock code at all."
    protected void gateLock(String showtimeId) { }
    protected void gateUnlock(String showtimeId) { }

    // For hold-keyed operations (confirm/cancel/sweep) we look up the showtime the
    // hold belongs to, then lock THAT showtime — so a hold operation and a seat
    // operation on the same showtime serialize. In the clean core, no-ops.
    protected void gateLockForHold(String holdId) {
        SeatHold hold = holds.get(holdId);
        if (hold != null) {
            gateLock(hold.showtimeId());
        }
    }

    protected void gateUnlockForHold(String holdId) {
        SeatHold hold = holds.get(holdId);
        if (hold != null) {
            gateUnlock(hold.showtimeId());
        }
    }
}

