package com.interview.lld.moviebooking.service;

import java.time.Duration;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.locks.ReentrantLock;

import com.interview.lld.moviebooking.gateway.Clock;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// The thread-safe version of the booking service. It adds ONE thing to the clean
// core: a per-showtime lock. Everything else — the two-phase check-then-hold, the
// expiry guard, the sweeper — is inherited unchanged.
//
// The key idea: I lock PER SHOWTIME, not one global lock. Two users booking seats
// in two DIFFERENT showtimes never block each other; only users fighting over
// seats in the SAME showtime serialize. That is the natural unit of contention.
//
// 🎙️ "The thread-safe service is a subclass. I override the two lock hooks to
//      grab a per-showtime lock. The whole two-phase check-and-hold runs under
//      that lock, so two users who want the same seat can never both win."
public class ThreadSafeBookingService extends BookingService {

    // showtime id -> its lock. ReentrantLock because a guarded method could call
    // another guarded method on the same thread; reentrancy lets it re-enter
    // instead of deadlocking on itself.
    private final Map<String, ReentrantLock> locks = new ConcurrentHashMap<>();

    public ThreadSafeBookingService(Clock clock) {
        super(clock);
    }

    public ThreadSafeBookingService(Clock clock, Duration holdDuration) {
        super(clock, holdDuration);
    }

    // WHY: computeIfAbsent on a ConcurrentHashMap is itself atomic, so two threads
    //      that first touch the same showtime get the SAME lock object — there is
    //      no race that could hand out two different locks for one showtime.
    //      That is the "lock the map of locks" idea, done safely with CHM.
    @Override
    protected void gateLock(String showtimeId) {
        ReentrantLock lock = locks.computeIfAbsent(showtimeId, id -> new ReentrantLock());
        lock.lock();
    }

    @Override
    protected void gateUnlock(String showtimeId) {
        // The lock for this showtime always exists by the time we unlock, because
        // gateLock created it. Held by THIS thread, so unlock() is safe.
        locks.get(showtimeId).unlock();
    }
}

package com.interview.lld.moviebooking;

import java.time.Duration;
import java.time.Instant;
import java.util.List;

import com.interview.lld.moviebooking.gateway.MutableClock;
import com.interview.lld.moviebooking.model.BookingException;
import com.interview.lld.moviebooking.model.SeatHold;
import com.interview.lld.moviebooking.model.SeatStatus;
import com.interview.lld.moviebooking.model.Showtime;
import com.interview.lld.moviebooking.model.Ticket;
import com.interview.lld.moviebooking.service.BookingService;
import com.interview.lld.moviebooking.service.ThreadSafeBookingService;

// ── WHY THIS CLASS ───────────────────────────────────────────────────────────
// A demo driver. It exercises the tricky cases the interviewer cares about:
// happy multi-seat booking, all-or-nothing rejection on a partial conflict,
// 10-minute hold expiry, and a concurrent stampede where many threads fight over
// the same seats and we prove NOBODY double-books.
public final class Main {

    private Main() { }

    public static void main(String[] args) throws Exception {
        // Fixed start time + fake clock so expiry is provable without sleeping.
        MutableClock clock = new MutableClock(Instant.parse("2026-06-21T18:00:00Z"));
        BookingService svc = new BookingService(clock);
        svc.addShowtime(new Showtime("show-1", "Dune Part Two",
                List.of("A1", "A2", "A3", "A4", "A5")));

        // ── Case 1: book multiple seats atomically (happy path) ──────────────
        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
        Ticket ticket = svc.confirmBooking(hold.holdId());
        assertTrue(ticket.seatLabels().equals(List.of("A1", "A2")), "Case 1 seats");
        assertTrue(svc.countByStatus("show-1", SeatStatus.BOOKED) == 2, "Case 1 booked count");
        System.out.println("Case 1 atomic multi-seat booking -> OK (ticket " + ticket.ticketId() + ")");

        // ── Case 2: all-or-nothing — A2 is booked, so {A2,A3} is fully rejected ─
        boolean rejected = false;
        try {
            svc.holdSeats("show-1", List.of("A2", "A3"));
        } catch (BookingException e) {
            rejected = true;
        }
        assertTrue(rejected, "Case 2 should reject");
        // A3 must NOT have been held — the whole request backed out cleanly.
        assertTrue(svc.countByStatus("show-1", SeatStatus.AVAILABLE) == 3, "Case 2 A3 untouched");
        System.out.println("Case 2 partial conflict rejected all-or-nothing -> OK");

        // ── Case 3: hold expires after 10 minutes if unpaid ──────────────────
        SeatHold staleHold = svc.holdSeats("show-1", List.of("A3", "A4"));
        assertTrue(svc.countByStatus("show-1", SeatStatus.HELD) == 2, "Case 3 held");
        clock.advance(Duration.ofMinutes(11));         // jump past the 10-min window
        int released = svc.sweepExpiredHolds();         // background cleanup
        assertTrue(released == 1, "Case 3 one hold swept");
        assertTrue(svc.countByStatus("show-1", SeatStatus.AVAILABLE) == 3, "Case 3 seats freed");
        boolean confirmFailed = false;
        try {
            svc.confirmBooking(staleHold.holdId());     // too late — hold is gone
        } catch (BookingException e) {
            confirmFailed = true;
        }
        assertTrue(confirmFailed, "Case 3 confirm after expiry fails");
        System.out.println("Case 3 unpaid hold expired after 10 min -> OK (released " + released + ")");

        // ── Case 4: invalid inputs rejected at the boundary ──────────────────
        assertThrows(() -> svc.holdSeats("ghost-show", List.of("A1")), "unknown showtime");
        assertThrows(() -> svc.holdSeats("show-1", List.of()), "empty seat list");
        assertThrows(() -> svc.holdSeats("show-1", List.of("Z9")), "unknown seat");
        System.out.println("Case 4 invalid inputs rejected -> OK");

        // ── Case 5: concurrent stampede — 40 threads fight for the same 2 seats ─
        concurrentStampede();

        System.out.println("ALL CASES PASSED");
    }

    // WHY: this is the proof that the two-phase commit under the per-showtime lock
    //      actually prevents double-booking. Many threads all try to hold the SAME
    //      pair of seats at the same instant. Exactly ONE may win.
    private static void concurrentStampede() throws Exception {
        int threads = 40;
        MutableClock clock = new MutableClock(Instant.parse("2026-06-21T18:00:00Z"));
        ThreadSafeBookingService svc = new ThreadSafeBookingService(clock);
        svc.addShowtime(new Showtime("show-2", "Oppenheimer",
                List.of("B1", "B2", "B3", "B4")));

        java.util.concurrent.CyclicBarrier gate = new java.util.concurrent.CyclicBarrier(threads);
        java.util.concurrent.atomic.AtomicInteger wins = new java.util.concurrent.atomic.AtomicInteger();
        var pool = java.util.concurrent.Executors.newFixedThreadPool(threads);
        for (int i = 0; i < threads; i++) {
            pool.submit(() -> {
                try {
                    gate.await();                       // everyone starts together
                    svc.holdSeats("show-2", List.of("B1", "B2"));
                    wins.incrementAndGet();
                } catch (BookingException ignored) {
                    // lost the race — expected for all but one thread
                } catch (Exception e) {
                    throw new RuntimeException(e);
                }
            });
        }
        pool.shutdown();
        assertTrue(pool.awaitTermination(10, java.util.concurrent.TimeUnit.SECONDS), "stampede done");
        assertTrue(wins.get() == 1, "exactly one hold won, got " + wins.get());
        // Exactly the two contested seats are HELD; the rest stay AVAILABLE.
        assertTrue(svc.countByStatus("show-2", SeatStatus.HELD) == 2, "two seats held");
        System.out.println("Case 5 stampede: " + threads + " threads, exactly 1 won -> OK");
    }

    private static void assertTrue(boolean cond, String message) {
        if (!cond) {
            throw new AssertionError("FAILED: " + message);
        }
    }

    private static void assertThrows(Runnable r, String message) {
        try {
            r.run();
            throw new AssertionError("FAILED: expected exception for " + message);
        } catch (BookingException expected) {
            // good
        }
    }
}

