import com.interview.lld.moviebooking.service.BookingService;
import com.interview.lld.moviebooking.service.ThreadSafeBookingService;

// JUnit 5 suite. Every public method has a happy-path test, every typed exception
// has its own test, plus the boundary, idempotency, expiry, and concurrency tests.
class BookingServiceTest {

    private static final Instant START = Instant.parse("2026-06-21T18:00:00Z");

    private MutableClock clock;
    private BookingService svc;

    @BeforeEach
    void setUp() {
        clock = new MutableClock(START);
        svc = new BookingService(clock);
        svc.addShowtime(new Showtime("show-1", "Dune Part Two",
                List.of("A1", "A2", "A3", "A4", "A5")));
    }

    // ── holdSeats + confirmBooking happy path ────────────────────────────────
    @Test
    void holdThenConfirmBooksAllSeats() {
        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
        assertEquals(2, svc.countByStatus("show-1", SeatStatus.HELD));

        Ticket ticket = svc.confirmBooking(hold.holdId());
        assertEquals(List.of("A1", "A2"), ticket.seatLabels());
        assertEquals("Dune Part Two", ticket.movieTitle());
        assertEquals(2, svc.countByStatus("show-1", SeatStatus.BOOKED));
        assertEquals(0, svc.liveHoldCount());
    }

    // ── all-or-nothing: a partial conflict rejects the WHOLE request ─────────
    @Test
    void partialConflictRejectsEntireRequestAndTouchesNothing() {
        svc.holdSeats("show-1", List.of("A2"));   // A2 now HELD

        SeatsUnavailableException ex = assertThrows(SeatsUnavailableException.class,
                () -> svc.holdSeats("show-1", List.of("A1", "A2", "A3")));
        assertEquals(List.of("A2"), ex.getConflictingSeats());

        // A1 and A3 must remain AVAILABLE — the request backed out cleanly.
        assertEquals(4, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
        assertEquals(1, svc.countByStatus("show-1", SeatStatus.HELD));
    }

    // ── typed exception: unknown showtime ────────────────────────────────────
    @Test
    void unknownShowtimeRejected() {
        assertThrows(UnknownShowtimeException.class,
                () -> svc.holdSeats("ghost", List.of("A1")));
    }

    // ── typed exception: empty request ───────────────────────────────────────
    @Test
    void emptySeatListRejected() {
        assertThrows(InvalidBookingException.class,
                () -> svc.holdSeats("show-1", List.of()));
    }

    // ── typed exception: unknown seat label ──────────────────────────────────
    @Test
    void unknownSeatLabelRejected() {
        assertThrows(InvalidBookingException.class,
                () -> svc.holdSeats("show-1", List.of("Z9")));
    }

    // ── typed exception: confirm an unknown hold ─────────────────────────────
    @Test
    void confirmUnknownHoldRejected() {
        assertThrows(InvalidBookingException.class,
                () -> svc.confirmBooking("hold-999"));
    }

    // ── expiry: an unpaid hold is released after 10 minutes ──────────────────
    @Test
    void unpaidHoldExpiresAndSeatsReturnToAvailable() {
        SeatHold hold = svc.holdSeats("show-1", List.of("A1", "A2"));
        assertEquals(2, svc.countByStatus("show-1", SeatStatus.HELD));

        clock.advance(Duration.ofMinutes(11));     // jump past the 10-min window
        int released = svc.sweepExpiredHolds();
        assertEquals(1, released);
        assertEquals(5, svc.countByStatus("show-1", SeatStatus.AVAILABLE));
        assertEquals(0, svc.liveHoldCount());

        // confirming the now-expired hold must fail.
        assertThrows(InvalidBookingException.class, () -> svc.confirmBooking(hold.holdId()));
    }

    // ── expiry guard: confirm just past the window fails even before a sweep ─
