    void confirmAfterExpiryWindowFailsWithoutSweep() {
        SeatHold hold = svc.holdSeats("show-1", List.of("A1"));
        clock.advance(Duration.ofMinutes(10));     // exactly at the boundary => expired
        assertThrows(InvalidBookingException.class, () -> svc.confirmBooking(hold.holdId()));
