    }

    // ── CONCURRENCY: many threads, overlapping seat sets, NO double-booking ──
    @Test
    void concurrentOverlappingHoldsNeverDoubleBook() throws Exception {
        int threads = 50;
        MutableClock c = new MutableClock(START);
        ThreadSafeBookingService tsvc = new ThreadSafeBookingService(c);
        tsvc.addShowtime(new Showtime("show-x", "Interstellar",
                List.of("S1", "S2", "S3", "S4")));

        // Every thread wants the SAME overlapping pair {S1, S2}. Only ONE can win.
        CyclicBarrier gate = new CyclicBarrier(threads);
        AtomicInteger wins = new AtomicInteger();
        AtomicInteger conflicts = new AtomicInteger();
        Set<String> winningHoldIds = ConcurrentHashMap.newKeySet();

        ExecutorService pool = Executors.newFixedThreadPool(threads);
        for (int i = 0; i < threads; i++) {
            pool.submit(() -> {
                try {
                    gate.await();                          // all hit the lock at once
                    SeatHold h = tsvc.holdSeats("show-x", List.of("S1", "S2"));
                    wins.incrementAndGet();
                    winningHoldIds.add(h.holdId());
                } catch (SeatsUnavailableException expected) {
                    conflicts.incrementAndGet();           // typed loss
                } catch (Exception e) {
                    throw new RuntimeException(e);
                }
            });
        }
        pool.shutdown();
        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS), "all threads finished");

        // Exactly one winner, all others lost with the TYPED exception (no surprises).
        assertEquals(1, wins.get(), "exactly one hold should win");
        assertEquals(1, winningHoldIds.size(), "winner has a unique hold id");
        assertEquals(threads - 1, conflicts.get(), "every loser got SeatsUnavailable");

        // Post-state: exactly the two contested seats are HELD, the rest AVAILABLE.
        assertEquals(2, tsvc.countByStatus("show-x", SeatStatus.HELD));
        assertEquals(2, tsvc.countByStatus("show-x", SeatStatus.AVAILABLE));
        assertEquals(1, tsvc.liveHoldCount());
    }

