                    gate.await();
                    tsvc.holdSeats("show-y", requests.get(idx));
                    wins.incrementAndGet();
                } catch (Exception e) {
                    throw new RuntimeException(e);
                }
            });
        }
        pool.shutdown();
        assertTrue(pool.awaitTermination(15, TimeUnit.SECONDS));
        assertEquals(4, wins.get(), "all disjoint requests succeed");
        assertEquals(4, tsvc.countByStatus("show-y", SeatStatus.HELD));
    }
}
